mapper.select:
select number from shopping_cart


        dish_id=#{dishId}


        and setmeal_id=#{setmealId}


        and dish_flavor=#{dishFlavor}


        and user_id=#{userId}


;

mapper.update:
update shopping_cart set number=#{number},create_time=#{createTime}


    and dish_id=#{dishId}


    and setmeal_id=#{setmealId}


    and dish_flavor=#{dishFlavor}


    and user_id=#{userId}


;

mapper.delete:
delete from shopping_cart


        and dish_id=#{dishId}


        and setmeal_id=#{setmealId}


        and user_id=#{userId} and number=1


;
